Here are the public test cases for feature2_1_outgoing_service_dependency:
{
  "description": "Parse an outgoing service dependency into name + redirect flag + idle/request timeouts (omitted timeouts fall back to a default).",
  "cases": [
    {
      "input": {
        "op": "outgoing_dependency",
        "service": "my-service"
      },
      "expected_output": "type=service\nservice=my-service\nhandleInternalRedirect=false\nidleTimeout=120s\nrequestTimeout=120s\n"
    },
    {
      "input": {
        "op": "outgoing_dependency",
        "service": "service-1",
        "idleTimeout": "10s"
      },
      "expected_output": "type=service\nservice=service-1\nhandleInternalRedirect=false\nidleTimeout=10s\nrequestTimeout=120s\n"
    }
  ]
}

Here are the public test cases for feature2_3_outgoing_dependency_validation:
{
  "description": "Reject dependencies that declare neither/both target kinds, or a domain with an unsupported scheme; emit neutral error category lines.",
  "cases": [
    {
      "input": {
        "op": "outgoing_dependency"
      },
      "expected_output": "error=invalid_dependency_target\n"
    },
    {
      "input": {
        "op": "outgoing_dependency",
        "domain": "ftp://domain"
      },
      "expected_output": "error=unsupported_domain_protocol\ndomain=ftp://domain\n"
    }
  ]
}
